document.addEventListener("DOMContentLoaded", function () {
  var navToggle = document.getElementById("nav-toggle");
  var navContent = document.getElementById("nav-content");
  var siteHeader = document.getElementById("site-header");
  var yearNode = document.getElementById("year");
  var projectsCountNode = document.getElementById("projects-count");
  var revealTargets = document.querySelectorAll(".reveal");

  if (yearNode) {
	yearNode.textContent = String(new Date().getFullYear());
  }

  var projects = Array.isArray(window.PROJECTS) ? window.PROJECTS.slice() : [];
  var projectsList = document.getElementById("projects-list");
  var projectCardTemplate = document.getElementById("project-card-template");
  var projectFilters = document.getElementById("project-filters");

  var sortProjects = function (list) {
	return list.sort(function (a, b) {
	  if (Boolean(a.featured) !== Boolean(b.featured)) {
		return a.featured ? -1 : 1;
	  }
	  return Number(b.year || 0) - Number(a.year || 0);
	});
  };

  var categories = ["Tous"];
  projects.forEach(function (project) {
	if (project.category && categories.indexOf(project.category) === -1) {
	  categories.push(project.category);
	}
  });

  var renderProjects = function (category) {
	if (!projectsList || !projectCardTemplate) {
	  return;
	}

	projectsList.innerHTML = "";

	var activeCategory = category || "Tous";
	var filtered = sortProjects(
	  projects.filter(function (project) {
		return activeCategory === "Tous" || project.category === activeCategory;
	  })
	);

	filtered.forEach(function (project) {
	  var fragment = projectCardTemplate.content.cloneNode(true);
	  var card = fragment.querySelector(".project-card");
	  var image = fragment.querySelector(".project-media");
	  var badge = fragment.querySelector(".project-featured-badge");
	  var title = fragment.querySelector(".project-title");
	  var year = fragment.querySelector(".project-year");
	  var categoryNode = fragment.querySelector(".project-category");
	  var description = fragment.querySelector(".project-description");
	  var tags = fragment.querySelector(".project-tags");
	  var link = fragment.querySelector(".project-link");

	  image.src = project.image || "";
	  image.alt = project.alt || project.title || "Projet";
	  title.textContent = project.title || "Projet";
	  year.textContent = project.year || "";
	  categoryNode.textContent = project.category || "Projet";
	  description.textContent = project.description || "";

	  if (Array.isArray(project.tags)) {
		project.tags.forEach(function (tag) {
		  var tagNode = document.createElement("span");
		  tagNode.textContent = tag;
		  tags.appendChild(tagNode);
		});
	  }

	  link.href = project.href || "#";
	  link.textContent = project.cta || "Voir le projet";
	  if (project.external) {
		link.target = "_blank";
		link.rel = "noreferrer";
	  }

	  if (!project.featured) {
		badge.remove();
	  } else {
		card.classList.add("is-featured");
	  }

	  projectsList.appendChild(fragment);
	});
  };

  if (projectsCountNode) {
	projectsCountNode.textContent = String(projects.length) + "+";
  }

  if (projectFilters && categories.length > 0) {
	var setActiveFilter = function (value) {
	  projectFilters.querySelectorAll("button").forEach(function (button) {
		var isActive = button.getAttribute("data-filter") === value;
		button.classList.toggle("is-active", isActive);
	  });
	};

	categories.forEach(function (category) {
	  var button = document.createElement("button");
	  button.type = "button";
	  button.className = "filter-chip";
	  button.setAttribute("data-filter", category);
	  button.textContent = category;
	  button.addEventListener("click", function () {
		renderProjects(category);
		setActiveFilter(category);
	  });
	  projectFilters.appendChild(button);
	});

	setActiveFilter("Tous");
  }

  renderProjects("Tous");

  if (navToggle && navContent) {
	navToggle.addEventListener("click", function () {
	  var isOpen = navContent.classList.toggle("is-open");
	  navToggle.setAttribute("aria-expanded", String(isOpen));
	});

	navContent.querySelectorAll("a").forEach(function (link) {
	  link.addEventListener("click", function () {
		navContent.classList.remove("is-open");
		navToggle.setAttribute("aria-expanded", "false");
	  });
	});
  }

  var updateHeaderState = function () {
	if (!siteHeader) {
	  return;
	}
	if (window.scrollY > 18) {
	  siteHeader.classList.add("is-scrolled");
	} else {
	  siteHeader.classList.remove("is-scrolled");
	}
  };

  updateHeaderState();
  window.addEventListener("scroll", updateHeaderState, { passive: true });

  if ("IntersectionObserver" in window) {
	var observer = new IntersectionObserver(
	  function (entries) {
		entries.forEach(function (entry) {
		  if (entry.isIntersecting) {
			entry.target.classList.add("in-view");
			observer.unobserve(entry.target);
		  }
		});
	  },
	  { threshold: 0.14 }
	);

	revealTargets.forEach(function (node) {
	  observer.observe(node);
	});
  } else {
	revealTargets.forEach(function (node) {
	  node.classList.add("in-view");
	});
  }
});

document.addEventListener("DOMContentLoaded", function () {
  var navToggle = document.getElementById("nav-toggle");
  var navContent = document.getElementById("nav-content");
  var siteHeader = document.getElementById("site-header");
  var yearNode = document.getElementById("year");
  var revealTargets = document.querySelectorAll(".reveal");

  if (yearNode) {
	yearNode.textContent = String(new Date().getFullYear());
  }

  if (navToggle && navContent) {
	navToggle.addEventListener("click", function () {
	  var isOpen = navContent.classList.toggle("is-open");
	  navToggle.setAttribute("aria-expanded", String(isOpen));
	});

	navContent.querySelectorAll("a").forEach(function (link) {
	  link.addEventListener("click", function () {
		navContent.classList.remove("is-open");
		navToggle.setAttribute("aria-expanded", "false");
	  });
	});
  }

  var updateHeaderState = function () {
	if (!siteHeader) {
	  return;
	}
	if (window.scrollY > 18) {
	  siteHeader.classList.add("is-scrolled");
	} else {
	  siteHeader.classList.remove("is-scrolled");
	}
  };

  updateHeaderState();
  window.addEventListener("scroll", updateHeaderState, { passive: true });

  if ("IntersectionObserver" in window) {
	var observer = new IntersectionObserver(
	  function (entries) {
		entries.forEach(function (entry) {
		  if (entry.isIntersecting) {
			entry.target.classList.add("in-view");
			observer.unobserve(entry.target);
		  }
		});
	  },
	  { threshold: 0.14 }
	);

	revealTargets.forEach(function (node) {
	  observer.observe(node);
	});
  } else {
	revealTargets.forEach(function (node) {
	  node.classList.add("in-view");
	});
  }
});

:root {
  --bg: #070910;
  --bg-soft: #0f1527;
  --text: #f5f8ff;
  --muted: #b5bfd4;
  --primary: #71a6ff;
  --primary-strong: #4a8fff;
  --glass: rgba(255, 255, 255, 0.08);
  --glass-border: rgba(255, 255, 255, 0.16);
  --radius-lg: 24px;
  --radius-md: 18px;
  --shadow: 0 12px 40px rgba(2, 6, 23, 0.45);
  --max-width: 1140px;
}

* {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  margin: 0;
  min-height: 100vh;
  font-family: Inter, Arial, sans-serif;
  color: var(--text);
  background: radial-gradient(circle at top, #121d36 0%, var(--bg) 45%);
  line-height: 1.6;
  overflow-x: hidden;
}

body::before {
  content: "";
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: -2;
  background-image: linear-gradient(
      rgba(148, 184, 255, 0.06) 1px,
      transparent 1px
    ),
    linear-gradient(90deg, rgba(148, 184, 255, 0.06) 1px, transparent 1px);
  background-size: 36px 36px;
  mask-image: radial-gradient(circle at center, #000 30%, transparent 85%);
}

a {
  color: inherit;
  text-decoration: none;
}

.shell {
  width: min(var(--max-width), calc(100% - 2.5rem));
  margin: 0 auto;
}

.site-header {
  position: sticky;
  top: 0;
  z-index: 20;
  padding-top: 0.9rem;
}

.site-header.is-scrolled .nav {
  box-shadow: var(--shadow);
}

.nav {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0.8rem 1rem;
  border-radius: var(--radius-md);
  border: 1px solid var(--glass-border);
  background: rgba(14, 20, 35, 0.8);
  backdrop-filter: blur(14px);
  -webkit-backdrop-filter: blur(14px);
  transition: box-shadow 0.25s ease;
}

.brand {
  display: inline-flex;
  align-items: center;
  gap: 0.65rem;
  font-weight: 700;
}

.brand img {
  width: 38px;
  height: 38px;
  border-radius: 11px;
}

.nav-content {
  display: flex;
  align-items: center;
  gap: 0.4rem;
}

.nav-content a {
  padding: 0.5rem 0.8rem;
  border-radius: 999px;
  color: var(--muted);
  transition: all 0.25s ease;
}

.nav-content a:hover,
.nav-content a:focus-visible {
  color: var(--text);
  background: rgba(255, 255, 255, 0.08);
  outline: none;
}

.nav-toggle {
  display: none;
  width: 42px;
  height: 42px;
  border: 1px solid var(--glass-border);
  border-radius: 12px;
  color: var(--text);
  background: rgba(255, 255, 255, 0.06);
  cursor: pointer;
}

.hero {
  position: relative;
  padding: 6rem 0 2rem;
}

.eyebrow {
  margin: 0;
  font-size: 0.86rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.13em;
  color: #96c1ff;
}

h1,
h2,
h3,
p {
  margin: 0;
}

h1 {
  margin-top: 0.75rem;
  font-size: clamp(2rem, 4.8vw, 4rem);
  line-height: 1.1;
}

h1 span {
  color: #bfd8ff;
}

.hero-text {
  margin-top: 1.25rem;
  max-width: 760px;
  color: var(--muted);
  font-size: clamp(1rem, 1.45vw, 1.2rem);
}

.hero-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 0.9rem;
  margin-top: 1.8rem;
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.72rem 1.2rem;
  border-radius: 999px;
  font-weight: 600;
  transition: transform 0.25s ease, box-shadow 0.25s ease, background 0.25s ease;
}

.btn:hover {
  transform: translateY(-2px);
}

.btn-primary {
  color: #01163a;
  background: linear-gradient(120deg, #9ac1ff, #6fa6ff 55%, #8ed5ff);
  box-shadow: 0 10px 30px rgba(113, 166, 255, 0.32);
}

.btn-glass {
  border: 1px solid var(--glass-border);
  background: rgba(255, 255, 255, 0.06);
}

.section {
  padding: 3rem 0;
}

.section-heading {
  margin-bottom: 1.1rem;
}

.section-heading h2 {
  margin-top: 0.45rem;
  font-size: clamp(1.45rem, 3.2vw, 2.25rem);
}

.section-subtitle {
  margin-top: 0.6rem;
  color: var(--muted);
}

.section-subtitle code {
  padding: 0.15rem 0.5rem;
  border-radius: 999px;
  border: 1px solid rgba(255, 255, 255, 0.2);
  background: rgba(255, 255, 255, 0.08);
  color: #dceaff;
}

.glass-card {
  border: 1px solid var(--glass-border);
  border-radius: var(--radius-lg);
  background: linear-gradient(
	130deg,
	rgba(255, 255, 255, 0.12),
	rgba(255, 255, 255, 0.04)
  );
  backdrop-filter: blur(18px);
  -webkit-backdrop-filter: blur(18px);
  box-shadow: var(--shadow);
}

.prose {
  padding: 1.4rem;
}

.prose p {
  color: var(--muted);
}

.prose p + p {
  margin-top: 1rem;
}

.stats-grid {
  margin-top: 1.8rem;
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 0.9rem;
}

.stat-card {
  padding: 1rem;
}

.stat-card strong {
  display: block;
  font-size: 1.3rem;
}

.stat-card span {
  color: var(--muted);
  font-size: 0.95rem;
}

.project-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 1rem;
}

.project-toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 0.8rem;
  margin-bottom: 1rem;
}

.project-filters {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
}

.filter-chip {
  border: 1px solid rgba(255, 255, 255, 0.2);
  background: rgba(255, 255, 255, 0.06);
  color: #d3e4ff;
  border-radius: 999px;
  padding: 0.4rem 0.72rem;
  cursor: pointer;
  transition: all 0.2s ease;
}

.filter-chip:hover,
.filter-chip.is-active {
  border-color: rgba(135, 184, 255, 0.7);
  background: rgba(113, 166, 255, 0.2);
  color: #f2f7ff;
}

.project-card {
  overflow: hidden;
  transition: transform 0.35s ease, border-color 0.35s ease, box-shadow 0.35s ease;
  position: relative;
}

.project-card:hover {
  transform: translateY(-6px);
  border-color: rgba(151, 194, 255, 0.55);
  box-shadow: 0 18px 45px rgba(16, 33, 63, 0.45);
}

.project-media-wrap {
  position: relative;
  overflow: hidden;
}

.project-media-wrap::after {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(125deg, transparent 35%, rgba(255, 255, 255, 0.25), transparent 65%);
  transform: translateX(-130%);
  transition: transform 0.8s ease;
}

.project-card:hover .project-media-wrap::after {
  transform: translateX(130%);
}

.project-media {
  width: 100%;
  height: 200px;
  object-fit: cover;
  display: block;
  transform: scale(1);
  transition: transform 0.6s ease;
}

.project-card:hover .project-media {
  transform: scale(1.04);
}

.project-featured-badge {
  position: absolute;
  top: 0.8rem;
  right: 0.8rem;
  border-radius: 999px;
  padding: 0.26rem 0.62rem;
  font-size: 0.75rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  font-weight: 700;
  color: #08214f;
  background: linear-gradient(120deg, #a5d9ff, #86b5ff);
}

.project-body {
  padding: 1rem;
}

.project-headline-row {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 0.7rem;
}

.project-title {
  margin-bottom: 0.35rem;
  font-size: 1.15rem;
}

.project-year {
  color: #9ebce8;
  font-size: 0.9rem;
}

.project-category {
  color: #accbfa;
  font-size: 0.88rem;
  margin-bottom: 0.4rem;
}

.project-description {
  color: var(--muted);
}

.project-tags {
  margin-top: 0.75rem;
  display: flex;
  flex-wrap: wrap;
  gap: 0.4rem;
}

.project-tags span {
  display: inline-flex;
  padding: 0.25rem 0.5rem;
  border: 1px solid rgba(255, 255, 255, 0.16);
  border-radius: 999px;
  font-size: 0.78rem;
  color: #cfe2ff;
  background: rgba(255, 255, 255, 0.05);
}

.project-link {
  display: inline-flex;
  margin-top: 0.8rem;
  color: #97c2ff;
  font-weight: 600;
}

.project-link::after {
  content: "\2192";
  margin-left: 0.4rem;
  transition: transform 0.2s ease;
}

.project-card:hover .project-link::after {
  transform: translateX(3px);
}

.skills-wrap {
  padding: 1rem;
  display: flex;
  flex-wrap: wrap;
  gap: 0.7rem;
}

.skills-wrap span {
  padding: 0.55rem 0.8rem;
  border: 1px solid rgba(255, 255, 255, 0.15);
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.06);
  color: #d6e5ff;
}

.contact-panel {
  padding: 1.2rem;
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 0.75rem;
}

.contact-panel a {
  display: flex;
  align-items: center;
  gap: 0.55rem;
  color: #d7e7ff;
  padding: 0.75rem 0.85rem;
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.05);
  transition: background 0.2s ease;
}

.contact-panel a:hover {
  background: rgba(255, 255, 255, 0.11);
}

.site-footer {
  padding: 2.5rem 0 2rem;
  color: #8f9bb2;
  text-align: center;
}

.background-orb {
  position: fixed;
  pointer-events: none;
  z-index: -1;
  width: 380px;
  height: 380px;
  border-radius: 50%;
  filter: blur(90px);
  opacity: 0.34;
  animation: orbFloat 12s ease-in-out infinite;
}

.orb-a {
  top: -120px;
  left: -120px;
  background: #5f8fff;
}

.orb-b {
  top: 25%;
  right: -90px;
  background: #58d3ff;
  animation-delay: -4s;
}

.orb-c {
  bottom: -140px;
  left: 35%;
  background: #8d68ff;
  animation-delay: -7s;
}

.reveal {
  opacity: 0;
  transform: translateY(24px);
  transition: transform 0.7s ease, opacity 0.7s ease;
}

.reveal.in-view {
  opacity: 1;
  transform: translateY(0);
}

.hero-project {
  padding: 6rem 0 2.5rem;
}

.project-layout {
  display: grid;
  grid-template-columns: 1fr;
  gap: 1rem;
}

.video-card {
  padding: 0.8rem;
}

.video-card iframe {
  width: 100%;
  min-height: 280px;
  border: 0;
  border-radius: 16px;
}

.project-points {
  padding: 1.1rem;
}

.project-points ul {
  margin: 0.6rem 0 0;
  padding-left: 1.2rem;
  color: var(--muted);
}

.project-points li + li {
  margin-top: 0.45rem;
}

@keyframes orbFloat {
  0%,
  100% {
	transform: translateY(0) scale(1);
  }
  50% {
	transform: translateY(-24px) scale(1.04);
  }
}

@media (max-width: 900px) {
  .stats-grid,
  .project-grid,
  .contact-panel {
	grid-template-columns: 1fr;
  }

  .nav-toggle {
	display: inline-flex;
	align-items: center;
	justify-content: center;
  }

  .nav-content {
	position: absolute;
	left: 1.25rem;
	right: 1.25rem;
	top: calc(100% + 0.5rem);
	border-radius: 16px;
	border: 1px solid var(--glass-border);
	background: rgba(14, 20, 35, 0.92);
	backdrop-filter: blur(18px);
	display: none;
	flex-direction: column;
	align-items: stretch;
	gap: 0;
	overflow: hidden;
  }

  .nav-content a {
	border-radius: 0;
	padding: 0.85rem 1rem;
  }

  .nav-content.is-open {
	display: flex;
  }
}

@media (min-width: 901px) {
  .project-layout {
	grid-template-columns: 1.35fr 1fr;
  }
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
	animation: none !important;
	transition: none !important;
	scroll-behavior: auto !important;
  }

  .reveal {
	opacity: 1;
	transform: none;
  }
}

