}

h1 {
  margin-top: 0.75rem;
  font-size: clamp(2rem, 4.8vw, 4rem);
  line-height: 1.1;
}

h1 span {
  color: #bfd8ff;
}

.hero-text {
  margin-top: 1.25rem;
  max-width: 760px;
  color: var(--muted);
  font-size: clamp(1rem, 1.45vw, 1.2rem);
}

.hero-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 0.9rem;
  margin-top: 1.8rem;
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.72rem 1.2rem;
  border-radius: 999px;
  font-weight: 600;
  transition: transform 0.25s ease, box-shadow 0.25s ease, background 0.25s ease;
}

.btn:hover {
  transform: translateY(-2px);
}

.btn-primary {
  color: #01163a;
  background: linear-gradient(120deg, #9ac1ff, #6fa6ff 55%, #8ed5ff);
  box-shadow: 0 10px 30px rgba(113, 166, 255, 0.32);
}

.btn-glass {
  border: 1px solid var(--glass-border);
  background: rgba(255, 255, 255, 0.06);
}

.section {
  padding: 3rem 0;
}

.section-heading {
  margin-bottom: 1.1rem;
}

.section-heading h2 {
  margin-top: 0.45rem;
  font-size: clamp(1.45rem, 3.2vw, 2.25rem);
}

.glass-card {
  border: 1px solid var(--glass-border);
  border-radius: var(--radius-lg);
  background: linear-gradient(
	130deg,
	rgba(255, 255, 255, 0.12),
	rgba(255, 255, 255, 0.04)
  );
  backdrop-filter: blur(18px);
  -webkit-backdrop-filter: blur(18px);
  box-shadow: var(--shadow);
}

.prose {
  padding: 1.4rem;
}

.prose p {
  color: var(--muted);
}

.prose p + p {
  margin-top: 1rem;
}

.stats-grid {
  margin-top: 1.8rem;
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 0.9rem;
}

.stat-card {
  padding: 1rem;
}

.stat-card strong {
  display: block;
  font-size: 1.3rem;
}

.stat-card span {
  color: var(--muted);
  font-size: 0.95rem;
}

.project-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 1rem;
}

.project-card {
  overflow: hidden;
  transition: transform 0.35s ease, border-color 0.35s ease;
}

.project-card:hover {
  transform: translateY(-6px);
  border-color: rgba(151, 194, 255, 0.55);
}

.project-card img {
  width: 100%;
  height: 200px;
  object-fit: cover;
  display: block;
}

.project-card div {
  padding: 1rem;
}

.project-card h3 {
  margin-bottom: 0.35rem;
  font-size: 1.15rem;
}

.project-card p {
  color: var(--muted);
}

.project-card a {
  display: inline-flex;
  margin-top: 0.8rem;
  color: #97c2ff;
  font-weight: 600;
}

.skills-wrap {
  padding: 1rem;
  display: flex;
  flex-wrap: wrap;
  gap: 0.7rem;
}

.skills-wrap span {
  padding: 0.55rem 0.8rem;
  border: 1px solid rgba(255, 255, 255, 0.15);
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.06);
  color: #d6e5ff;
}

.contact-panel {
  padding: 1.2rem;
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 0.75rem;
}

.contact-panel a {
  display: flex;
  align-items: center;
  gap: 0.55rem;
  color: #d7e7ff;
  padding: 0.75rem 0.85rem;
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.05);
  transition: background 0.2s ease;
}

.contact-panel a:hover {
  background: rgba(255, 255, 255, 0.11);
}

.site-footer {
  padding: 2.5rem 0 2rem;
  color: #8f9bb2;
  text-align: center;
}

.background-orb {
  position: fixed;
  pointer-events: none;
  z-index: -1;
  width: 380px;
  height: 380px;
  border-radius: 50%;
  filter: blur(90px);
  opacity: 0.34;
  animation: orbFloat 12s ease-in-out infinite;
}

.orb-a {
  top: -120px;
  left: -120px;
  background: #5f8fff;
}

.orb-b {
  top: 25%;
  right: -90px;
  background: #58d3ff;
  animation-delay: -4s;
}

.orb-c {
  bottom: -140px;
  left: 35%;
  background: #8d68ff;
  animation-delay: -7s;
}

.reveal {
  opacity: 0;
  transform: translateY(24px);
  transition: transform 0.7s ease, opacity 0.7s ease;
}

.reveal.in-view {
  opacity: 1;
  transform: translateY(0);
}

.hero-project {
  padding: 6rem 0 2.5rem;
}

.project-layout {
  display: grid;
  grid-template-columns: 1fr;
  gap: 1rem;
}

.video-card {
  padding: 0.8rem;
}

.video-card iframe {
  width: 100%;
  min-height: 280px;
  border: 0;
  border-radius: 16px;
}

.project-points {
  padding: 1.1rem;
}

.project-points ul {
  margin: 0.6rem 0 0;
  padding-left: 1.2rem;
  color: var(--muted);
}

.project-points li + li {
  margin-top: 0.45rem;
}

@keyframes orbFloat {
  0%,
  100% {
	transform: translateY(0) scale(1);
  }
  50% {
	transform: translateY(-24px) scale(1.04);
  }
}

@media (max-width: 900px) {
  .stats-grid,
  .project-grid,
  .contact-panel {
	grid-template-columns: 1fr;
  }

  .nav-toggle {
	display: inline-flex;
	align-items: center;
	justify-content: center;
  }

  .nav-content {
	position: absolute;
	left: 1.25rem;
	right: 1.25rem;
	top: calc(100% + 0.5rem);
	border-radius: 16px;
	border: 1px solid var(--glass-border);
	background: rgba(14, 20, 35, 0.92);
	backdrop-filter: blur(18px);
	display: none;
	flex-direction: column;
	align-items: stretch;
	gap: 0;
	overflow: hidden;
  }

  .nav-content a {
	border-radius: 0;
	padding: 0.85rem 1rem;
  }

  .nav-content.is-open {
	display: flex;
  }
}

@media (min-width: 901px) {
  .project-layout {
	grid-template-columns: 1.35fr 1fr;
  }
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
	animation: none !important;
	transition: none !important;
	scroll-behavior: auto !important;
  }

  .reveal {
	opacity: 1;
	transform: none;
  }
}
